CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TABLE profiles (id UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE, username TEXT UNIQUE NOT NULL, display_name TEXT, avatar_url TEXT, target_score INT DEFAULT 730, current_level TEXT DEFAULT 'foundation', xp INT DEFAULT 0, streak_days INT DEFAULT 0, last_study_date DATE, role TEXT DEFAULT 'user', daily_goal INT DEFAULT 10, reminder_time TIME, onboarding_completed BOOLEAN DEFAULT FALSE, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE topics (id SERIAL PRIMARY KEY, slug TEXT UNIQUE NOT NULL, name_vi TEXT NOT NULL, name_en TEXT NOT NULL, icon TEXT, color TEXT, sort_order INT DEFAULT 0);
CREATE TABLE words (id SERIAL PRIMARY KEY, word TEXT NOT NULL, phonetic TEXT, word_type TEXT NOT NULL, meaning_vi TEXT NOT NULL, meaning_en TEXT, example_sentence TEXT NOT NULL, example_vi TEXT, synonyms TEXT[], confusables TEXT[], collocations TEXT[], level TEXT NOT NULL, topic_id INT REFERENCES topics(id), toeic_parts INT[], audio_url TEXT, is_active BOOLEAN DEFAULT TRUE, report_count INT DEFAULT 0, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE INDEX idx_words_level ON words(level); CREATE INDEX idx_words_topic ON words(topic_id);
CREATE TABLE user_words (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES profiles(id) ON DELETE CASCADE, word_id INT REFERENCES words(id) ON DELETE CASCADE, status TEXT DEFAULT 'new', stability FLOAT DEFAULT 0, difficulty FLOAT DEFAULT 0, elapsed_days INT DEFAULT 0, scheduled_days INT DEFAULT 0, reps INT DEFAULT 0, lapses INT DEFAULT 0, state INT DEFAULT 0, due TIMESTAMPTZ DEFAULT NOW(), last_review TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW(), UNIQUE(user_id, word_id));
CREATE INDEX idx_user_words_due ON user_words(user_id, due); CREATE INDEX idx_user_words_status ON user_words(user_id, status);
CREATE TABLE review_logs (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES profiles(id) ON DELETE CASCADE, word_id INT REFERENCES words(id), rating INT NOT NULL, state_before INT, state_after INT, due_before TIMESTAMPTZ, due_after TIMESTAMPTZ, elapsed_days INT, session_type TEXT, reviewed_at TIMESTAMPTZ DEFAULT NOW());
CREATE INDEX idx_review_logs_user ON review_logs(user_id, reviewed_at DESC);
CREATE TABLE sessions (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES profiles(id) ON DELETE CASCADE, session_type TEXT NOT NULL, words_studied INT DEFAULT 0, correct_count INT DEFAULT 0, xp_earned INT DEFAULT 0, duration_secs INT, started_at TIMESTAMPTZ DEFAULT NOW(), ended_at TIMESTAMPTZ);
CREATE TABLE word_reports (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, word_id INT REFERENCES words(id), user_id UUID REFERENCES profiles(id), reason TEXT NOT NULL, note TEXT, status TEXT DEFAULT 'pending', created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE achievements (id SERIAL PRIMARY KEY, slug TEXT UNIQUE NOT NULL, name_vi TEXT NOT NULL, description TEXT, icon TEXT, xp_reward INT DEFAULT 0, condition_type TEXT, condition_value INT);
CREATE TABLE user_achievements (user_id UUID REFERENCES profiles(id), achievement_id INT REFERENCES achievements(id), earned_at TIMESTAMPTZ DEFAULT NOW(), PRIMARY KEY (user_id, achievement_id));
CREATE TABLE leaderboard_cache (period TEXT NOT NULL, user_id UUID REFERENCES profiles(id), xp INT DEFAULT 0, rank INT, flashcard_xp INT DEFAULT 0, quiz_xp INT DEFAULT 0, streak_bonus INT DEFAULT 0, updated_at TIMESTAMPTZ DEFAULT NOW(), PRIMARY KEY(period,user_id));
CREATE TABLE push_subscriptions (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, user_id UUID REFERENCES profiles(id) ON DELETE CASCADE, endpoint TEXT NOT NULL, p256dh TEXT NOT NULL, auth TEXT NOT NULL, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE OR REPLACE FUNCTION set_updated_at() RETURNS TRIGGER AS $$ BEGIN NEW.updated_at = NOW(); RETURN NEW; END; $$ LANGUAGE plpgsql; CREATE TRIGGER words_updated_at BEFORE UPDATE ON words FOR EACH ROW EXECUTE FUNCTION set_updated_at();
